class Solution:
    def shiftGrid(self, grid, k):
        m, n = len(grid), len(grid[0])
        total = m * n
        result = [[0] * n for _ in range(m)]
        for r in range(m):
            for c in range(n):
                flat_idx = r * n + c
                new_flat = (flat_idx + k) % total
                nr, nc = divmod(new_flat, n)
                result[nr][nc] = grid[r][c]
        return result

