var shiftGrid = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const flat = grid.flat();
    const total = m * n;
    const shift = k % total;
    const rotated = shift ? [...flat.slice(-shift), ...flat.slice(0, -shift)] : flat;
    const result = [];
    for (let i = 0; i < m; i++) result.push(rotated.slice(i * n, (i + 1) * n));
    return result;
};
